#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long ll;
const int N=2e5+10;int a[N],b[N],n,m,X,Y,px[N],py[N];
inline bool check(int Z)
{
	if(a[X]+b[Y]<=Z)return true;
	py[0]=m;rep(1,n,i){py[i]=py[i-1];while(py[i]&&a[i]+b[py[i]]>Z)--py[i];}
	px[0]=n;rep(1,m,i){px[i]=px[i-1];while(px[i]&&a[px[i]]+b[i]>Z)--px[i];}
	ll sum=0,m0=0,m1=0;int cy=m;rep(1,m,i)sum+=px[i];
	drep(n,0,i)
	{
		int cx=i;sum+=m-max(cy,py[i+1])-min(cy,py[i+1]);
		while(cx)
		{
			ll tmp=n-max(cx,px[cy])-min(cx,px[cy]);
			if(tmp<=0)break;sum+=tmp;--cy;
		}
		m0=max(m0,sum);m1=max(m1,sum-(cx<X&&cy<Y));
	}
	return m0==m1;
}
int main()
{
	n=read();m=read();rep(1,n,i)a[i]=read();rep(1,m,i)b[i]=read();
	X=a[1];Y=b[1];sort(a+1,a+n+1);sort(b+1,b+m+1);
	drep(n,1,i)if(a[i]==X){X=i;break;} drep(m,1,i)if(b[i]==Y){Y=i;break;}
	int l=a[1]+b[1],r=a[n]+b[m],mid;while(l<=r)check(mid=(l+r)>>1)?r=mid-1:l=mid+1;
	printf("%d\n",r+1);return 0;
}
